import openpyxl
from openpyxl import load_workbook

# Load the workbook
wb = load_workbook('/tmp/tmp05lzvuvy/1_267-21_init.xlsx')

# Get the sheets
sh1 = wb['SH1']
rp1 = wb['RP1']
merging = wb['merging']

# Create dictionaries for lookup from SH1 and RP1
# Key: ID, Value: QTY
sh1_dict = {}
for row in range(2, sh1.max_row + 1):
    id_val = sh1.cell(row, 2).value  # Column B (ID)
    qty_val = sh1.cell(row, 3).value  # Column C (QTY)
    if id_val:
        sh1_dict[id_val] = qty_val

rp1_dict = {}
for row in range(2, rp1.max_row + 1):
    id_val = rp1.cell(row, 2).value  # Column B (ID)
    qty_val = rp1.cell(row, 3).value  # Column C (QTY)
    if id_val:
        rp1_dict[id_val] = qty_val

# Process the merging sheet
for row in range(2, merging.max_row + 1):
    id_val = merging.cell(row, 2).value  # Column B (ID)

    if id_val:
        # Look up in SH1
        if id_val in sh1_dict and sh1_dict[id_val] is not None:
            merging.cell(row, 3).value = sh1_dict[id_val]  # Column C (MONTH1)
        else:
            merging.cell(row, 3).value = "-"

        # Look up in RP1
        if id_val in rp1_dict and rp1_dict[id_val] is not None:
            merging.cell(row, 4).value = rp1_dict[id_val]  # Column D (MONTH2)
        else:
            merging.cell(row, 4).value = "-"
    else:
        merging.cell(row, 3).value = "-"
        merging.cell(row, 4).value = "-"

# Save the workbook
wb.save('/tmp/tmp05lzvuvy/1_267-21_output.xlsx')

