import openpyxl
from openpyxl import load_workbook

# Load the workbook
wb = load_workbook('/tmp/tmpwus1kmp0/1_55049_init.xlsx')

# Get the sheets
book1 = wb['book1']
book2 = wb['book2']

# Get all Place values from book2 (column A) and their corresponding H, I, J values
book2_data = {}
for row in range(2, book2.max_row + 1):  # Start from row 2 (skip header)
    place = book2.cell(row, 1).value  # Column A
    if place:
        # Get values from columns H (8), I (9), J (10)
        h_val = book2.cell(row, 8).value or 0
        i_val = book2.cell(row, 9).value or 0
        j_val = book2.cell(row, 10).value or 0

        # Convert to numbers if they're strings
        try:
            h_val = float(h_val) if h_val != '' else 0
        except:
            h_val = 0
        try:
            i_val = float(i_val) if i_val != '' else 0
        except:
            i_val = 0
        try:
            j_val = float(j_val) if j_val != '' else 0
        except:
            j_val = 0

        # Sum across the three columns for this place
        if place in book2_data:
            book2_data[place] += h_val + i_val + j_val
        else:
            book2_data[place] = h_val + i_val + j_val

# Now fill in book1 column B with the sums
for row in range(3, book1.max_row + 1):  # Start from row 3
    place = book1.cell(row, 1).value  # Column A
    if place and place in book2_data:
        book1.cell(row, 2).value = book2_data[place]
    else:
        book1.cell(row, 2).value = 0

# Save the workbook
wb.save('/tmp/tmpwus1kmp0/1_55049_output.xlsx')

