import openpyxl
from openpyxl import load_workbook

# Load the workbook
wb = load_workbook('/tmp/tmp8o7b8iio/1_54196_init.xlsx')

# Select Sheet two
ws = wb['Sheet two']

# Find the last row of the table in columns B:E
last_row_table = 1
for row in range(2, ws.max_row + 1):
    if ws[f'B{row}'].value is not None:
        last_row_table = row
    else:
        break

# Create a lookup dictionary from column B (Supplier #) to column C (Estimated Delivery time)
lookup_dict = {}
for row in range(2, last_row_table + 1):
    supplier_num = ws[f'B{row}'].value
    delivery_time = ws[f'C{row}'].value
    if supplier_num is not None:
        # Store both as string and as number for flexible matching
        lookup_dict[str(supplier_num)] = delivery_time
        try:
            lookup_dict[int(supplier_num)] = delivery_time
        except (ValueError, TypeError):
            pass

# Now populate column E by looking up values from column G
for row in range(2, last_row_table + 1):
    supplier_value = ws[f'G{row}'].value

    if supplier_value is not None:
        # Try to find a match in the lookup dictionary
        result = None

        # Try direct match
        if supplier_value in lookup_dict:
            result = lookup_dict[supplier_value]
        # Try as string
        elif str(supplier_value) in lookup_dict:
            result = lookup_dict[str(supplier_value)]
        # Try converting to int
        else:
            try:
                if int(supplier_value) in lookup_dict:
                    result = lookup_dict[int(supplier_value)]
            except (ValueError, TypeError):
                pass

        # If no match found, leave as #N/A or empty
        if result is not None:
            ws[f'E{row}'].value = result
        else:
            ws[f'E{row}'].value = '#N/A'
    else:
        ws[f'E{row}'].value = '#N/A'

# Save the workbook
wb.save('/tmp/tmp8o7b8iio/1_54196_output.xlsx')
